-- 1) CREATE TABLES
CREATE TABLE IF NOT EXISTS users (
    user_id UUID PRIMARY KEY,
    username VARCHAR NOT NULL UNIQUE,
    phonenumber VARCHAR UNIQUE,
    phonenumber_encrypted VARCHAR,
    phonenumber_hash VARCHAR(64),
    email_encrypted VARCHAR,
    email_hash VARCHAR(64),
    full_name VARCHAR NOT NULL,
    role VARCHAR(30) NOT NULL DEFAULT 'customer',
    hashed_password VARCHAR NOT NULL,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS accounts (
    account_id UUID PRIMARY KEY,
    user_id UUID NOT NULL REFERENCES users(user_id) ON DELETE CASCADE,
    bank_name VARCHAR NOT NULL,
    account_number_masked VARCHAR NOT NULL,
    account_number_encrypted VARCHAR,
    account_number_hash VARCHAR(64),
    account_type VARCHAR NOT NULL,
    balance NUMERIC(12,2) NOT NULL
);

CREATE TABLE IF NOT EXISTS transactions (
    transaction_id UUID PRIMARY KEY,
    account_id UUID NOT NULL REFERENCES accounts(account_id) ON DELETE CASCADE,
    date TIMESTAMPTZ NOT NULL,
    amount NUMERIC(10,2) NOT NULL,
    currency VARCHAR(3) NOT NULL,
    type VARCHAR(10) NOT NULL,
    status VARCHAR(15) NOT NULL,
    category_purpose_code VARCHAR(4) NOT NULL DEFAULT 'OTHR',
    mcc INTEGER NOT NULL DEFAULT 5999,
    proprietary_bank_code VARCHAR(20) NOT NULL DEFAULT 'GIBL-FT-01',
    description VARCHAR,
    merchant VARCHAR,
    merchant_logo_url VARCHAR,
    merchant_verified_status BOOLEAN NOT NULL DEFAULT false,
    category VARCHAR
);

CREATE TABLE IF NOT EXISTS stock_instruments (
    id UUID PRIMARY KEY,
    user_id VARCHAR(64) NOT NULL,
    symbol VARCHAR(20) NOT NULL,
    name VARCHAR(255),
    quantity NUMERIC(18,6) NOT NULL DEFAULT 0,
    average_buy_price NUMERIC(18,6),
    current_price NUMERIC(18,6),
    currency VARCHAR(10),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_stock_instruments_user_id_id UNIQUE (user_id, id),
    CONSTRAINT uq_stock_instruments_user_id_symbol UNIQUE (user_id, symbol)
);

CREATE TABLE IF NOT EXISTS idempotency_records (
    id UUID PRIMARY KEY,
    idempotency_key VARCHAR(128) NOT NULL UNIQUE,
    endpoint VARCHAR(128) NOT NULL,
    request_hash VARCHAR(64) NOT NULL,
    response_status_code INTEGER NOT NULL,
    response_body VARCHAR NOT NULL,
    created_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS ix_users_username ON users (username);
CREATE INDEX IF NOT EXISTS ix_users_phonenumber ON users (phonenumber);
CREATE INDEX IF NOT EXISTS ix_users_phonenumber_hash ON users (phonenumber_hash);
CREATE INDEX IF NOT EXISTS ix_stock_instruments_user_id ON stock_instruments (user_id);

